function useGetSyllabus(category) {
  return useQuery({
    queryKey: ["syllabus", category],
    queryFn: () => {
      const entry = SYLLABUS_DATA.find((s) => s.category === category);
      return entry ?? { subjects: [], category };
    },
    staleTime: Number.POSITIVE_INFINITY
  });
}
function useGetQuestionPapers(category, subject) {
  return useQuery({
    queryKey: ["papers", category, subject],
    queryFn: () => {
      const entry = PAPERS_DATA.find(
        (p) => p.category === category && p.subject === subject
      );
      return (entry == null ? void 0 : entry.papers) ?? [];
    },
    enabled: subject !== "",
    staleTime: Number.POSITIVE_INFINITY
  });
}
function useSearchQABank(keyword) {
  return useQuery({
    queryKey: ["qa-bank-search", keyword],
    queryFn: () => {
      const q = keyword.trim().toLowerCase();
      if (!q) return [];
      return QA_BANK.filter(
        (e) => e.question.toLowerCase().includes(q) || e.answer.toLowerCase().includes(q)
      );
    },
    enabled: keyword.trim() !== "",
    staleTime: Number.POSITIVE_INFINITY
  });
}
function useGetQABySubject(category, subject) {
  return useQuery({
    queryKey: ["qa-bank-subject", category, subject],
    queryFn: () => {
      if (!subject) return [];
      return QA_BANK.filter(
        (e) => e.category === category && e.subject === subject
      );
    },
    enabled: subject !== "",
    staleTime: Number.POSITIVE_INFINITY
  });
}
function useGetQAByChapter(category, subject, chapter) {
  return useQuery({
    queryKey: ["qa-bank-chapter", category, subject, chapter],
    queryFn: () => {
      if (!chapter) return [];
      return QA_BANK.filter(
        (e) => e.category === category && e.subject === subject && (e.chapter ?? "") === chapter
      );
    },
    enabled: !!chapter,
    staleTime: Number.POSITIVE_INFINITY
  });
}
function useSearchGlossary(keyword) {
  return useQuery({
    queryKey: ["glossary", keyword],
    queryFn: () => {
      const q = keyword.trim().toLowerCase();
      if (!q) return GLOSSARY;
      return GLOSSARY.filter(
        (t) => t.term.toLowerCase().includes(q) || t.definition.toLowerCase().includes(q)
      );
    },
    staleTime: Number.POSITIVE_INFINITY
  });
}
export {
  QA_BANK as Q,
  useGetQuestionPapers as a,
  useSearchQABank as b,
  useGetQABySubject as c,
  useGetQAByChapter as d,
  useSearchGlossary as e,
  useGetSyllabus as u
};
